query.sparql:
SELECT ?answer WHERE {
  ?answer wdt:P451 wd:Q4463198;  # Triss Merigold
          wdt:P451 wd:Q4205826.  # Yennefer of Vengerberg
}

SELECT DISTINCT ?founder WHERE {
  wd:Q860580 wdt:P112 ?founder. # Founders of Tencent
  ?founder wdt:P102 ?party. # Member of a political party
  ?party wdt:P463 wd:Q19211. # Political party is part of National People's Congress
}

SELECT DISTINCT ?answer WHERE {
  ?answer wdt:P50 wd:Q550311;  # Works authored by Yoshihiro Togashi
          wdt:P921 ?subject.   # Main subject of the work
  ?subject rdfs:label "middle school student"@en.  # Filter for "middle school students"
}
